    results_output["old_model"] = {
        "metrics": old_metrics,
        "best": old_sorted[-TOP_N:][::-1],
        "worst": old_sorted[:TOP_N]
    }
    results_output["new_model"] = {
        "metrics": new_metrics,
        "best": new_sorted[-TOP_N:][::-1],
        "worst": new_sorted[:TOP_N]
    }

    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        json.dump(results_output, f, indent=2)

